output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?person ?personLabel WHERE {
  wd:Q524504 rdfs:label ?personLabel .
  FILTER(LANG(?personLabel) = 'en')
}

args.sparql:
SELECT ?whistleblower ?whistleblowerLabel
WHERE {
  ?whistleblower wdt:P31 wd:Q221783 .  # Instance of whistleblower
  ?whistleblower wdt:P106 ?occupation .
  ?occupation rdfs:label ?occupationLabel .
  FILTER (LANG(?occupationLabel) = 'en')
  FILTER (CONTAINS(LCASE(?occupationLabel), 'nuclear'))
  SERVICE wikibase:label { bd:serviceParam wikibase:language 'en' }
}

SELECT ?whistleblower ?whistleblowerLabel
WHERE {
  ?whistleblower wdt:P31 wd:Q5235694 .  # Instance of 'nuclear whistleblower'
  SERVICE wikibase:label { bd:serviceParam wikibase:language 'en' . }
}
